@namespace sv_e0103f805eb146f883c00922f7b682be.Components.Pages.Apply

<nav class="mb-4" aria-label="Application progress">
    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep;

            <div class="text-center flex-fill">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepCircleClass(step)"
                        style="width: 40px; height: 40px; font-size: 0.85rem;"
                        disabled="@isFuture"
                        @onclick="() => OnStepClicked(step)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </button>
                <div class="small mt-1 @(isCurrent ? "fw-bold" : "") @(isFuture ? "text-muted" : "")">
                    @StepNames[step]
                </div>
            </div>
        }
    </div>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<int> OnNavigate { get; set; }

    private string StepCircleClass(int step)
    {
        if (step < CurrentStep) return "btn-success text-white";
        if (step == CurrentStep) return "btn-primary text-white";
        return "btn-outline-secondary";
    }

    private async Task OnStepClicked(int step)
    {
        if (step < CurrentStep)
        {
            await OnNavigate.InvokeAsync(step);
        }
    }
}

@namespace sv_e0103f805eb146f883c00922f7b682be.Components.Pages.Apply

