@code {
    [Parameter, EditorRequired]
    public List<WorkEntryModel> Entries { get; set; } = [];

    [Parameter, EditorRequired]
    public EventCallback OnNext { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnBack { get; set; }

    private string? ValidationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
    }

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
    }

    private void HandleNext()
    {
        ValidationError = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title)
                || entry.StartDate == default)
            {
                ValidationError = "Company, job title, and start date are required for each position.";
                return;
            }
        }
        OnNext.InvokeAsync();
    }

    private static string FormatDate(DateTime? date) =>
        date?.ToString("yyyy-MM-dd") ?? "";

    private static string FormatDate(DateTime date) =>
        date == default ? "" : date.ToString("yyyy-MM-dd");

    private static DateTime ParseDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : default;

    private static DateTime? ParseNullableDate(object? value) =>
        DateTime.TryParse(value?.ToString(), out var d) ? d : null;

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}
