@page "/apply"
@using sv_e0103f805eb146f883c00922f7b682be.Components.Pages.Apply
@using sv_e0103f805eb146f883c00922f7b682be.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnNavigate="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep @bind-FullName="fullName"
                              @bind-Email="email"
                              @bind-Phone="phone"
                              @bind-Address="address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep References="references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetter="coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep FullName="@fullName"
                        Email="@email"
                        Phone="@phone"
                        Address="@address"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="@coverLetter"
                        OnEdit="GoToStep"
                        OnBack="PreviousStep"
                        SubmitApplication="SubmitAsync" />
            break;
    }
</div>

@code {
    private int currentStep;

    // Step 1 state
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2 state
    private List<WorkHistoryStep.WorkEntryModel> workEntries = [new()];

    // Step 3 state
    private List<ReferencesStep.ReferenceModel> references = [new(), new()];

    // Step 4 state
    private string coverLetter = "";

    private void NextStep() => currentStep = Math.Min(currentStep + 1, 4);
    private void PreviousStep() => currentStep = Math.Max(currentStep - 1, 0);
    private void GoToStep(int step) => currentStep = Math.Clamp(step, 0, 4);

    private async Task<int> SubmitAsync()
    {
        var application = new JobApplication(
            new PersonalInfo(fullName, email, phone, address),
            new WorkHistory(workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate,
                e.IsCurrent ? null : e.EndDate,
                e.Description)).ToList()),
            references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

